(function(){const WALINE_CONTAINER_SELECTOR='#waline';const WALINE_MODULE_URL='https://help-site.oss-cn-hangzhou.aliyuncs.com/js/waline.js';const CONTAINER_RETRY_DELAY=100;const CONTAINER_MAX_RETRY_COUNT=20;const MATERIAL_OBSERVER_POLL_INTERVAL=100;const MATERIAL_OBSERVER_MAX_WAIT_COUNT=100;const DOM_OBSERVER_DEBOUNCE=80;let walineModulePromise=null;let walineInstance=null;let walineContainer=null;let initSequence=0;let containerRetryTimer=null;let pageChangeSubscribed=false;let observerWaitTimer=null;let domObserver=null;let mountScheduleTimer=null;const locale={placeholder:'欢迎评论（登录后才可发布评论）',oldest:'最早评论',latest:'最新评论',hottest:'点赞量最多'};function loadWalineModule(){if(!walineModulePromise){walineModulePromise=import(WALINE_MODULE_URL).catch((error)=>{walineModulePromise=null;throw error;});}
return walineModulePromise;}
function clearWalineContainer(){if(walineContainer){walineContainer.textContent='';}}
function destroyWalineInstance(){if(walineInstance&&typeof walineInstance.destroy==='function'){walineInstance.destroy();}
walineInstance=null;clearWalineContainer();}
function clearContainerRetryTimer(){if(containerRetryTimer!==null){window.clearTimeout(containerRetryTimer);containerRetryTimer=null;}}
function scheduleRetry(retryCount){clearContainerRetryTimer();containerRetryTimer=window.setTimeout(()=>{void mountWaline(retryCount+1);},CONTAINER_RETRY_DELAY);}
function afterNextPaint(callback){window.requestAnimationFrame(()=>{window.requestAnimationFrame(callback);});}
function clearMountScheduleTimer(){if(mountScheduleTimer!==null){window.clearTimeout(mountScheduleTimer);mountScheduleTimer=null;}}
function scheduleMountWaline(){clearMountScheduleTimer();mountScheduleTimer=window.setTimeout(()=>{mountScheduleTimer=null;afterNextPaint(()=>{void mountWaline();});},DOM_OBSERVER_DEBOUNCE);}
function shouldAttemptMount(){const container=document.querySelector(WALINE_CONTAINER_SELECTOR);if(!container){return walineContainer!==null||walineInstance!==null;}
return(container!==walineContainer||walineInstance===null||container.childElementCount===0);}
async function mountWaline(retryCount=0){if(walineContainer&&!walineContainer.isConnected){walineContainer=null;walineInstance=null;}
const container=document.querySelector(WALINE_CONTAINER_SELECTOR);if(!container){if(retryCount<CONTAINER_MAX_RETRY_COUNT){scheduleRetry(retryCount);return;}
clearContainerRetryTimer();destroyWalineInstance();walineContainer=null;return;}
clearContainerRetryTimer();if(container===walineContainer&&walineInstance&&container.childElementCount>0){return;}
const currentSequence=++initSequence;destroyWalineInstance();walineContainer=container;try{const{init}=await loadWalineModule();if(currentSequence!==initSequence||walineContainer!==container){return;}
container.textContent='';walineInstance=init({el:container,path:window.location.pathname,serverURL:'https://waline-comment.netlify.app/.netlify/functions/comment',dark:'html[data-force-dark-theme]:not([data-force-dark-theme="off"])',emoji:['https://unpkg.com/@waline/emojis@1.2.0/bilibili','https://unpkg.com/@waline/emojis@1.2.0/bmoji','https://unpkg.com/@waline/emojis@1.2.0/qq','https://unpkg.com/@waline/emojis@1.2.0/tw-emoji','https://unpkg.com/@waline/emojis@1.2.0/weibo'],lang:'zh-CN',comment:true,search:false,meta:[],requiredMeta:[],login:'force',pageSize:3,noCopyright:true,locale});}catch(error){if(currentSequence!==initSequence){return;}
console.error('[waline] 初始化失败',error);}}
function clearObserverWaitTimer(){if(observerWaitTimer!==null){window.clearInterval(observerWaitTimer);observerWaitTimer=null;}}
function trySubscribeToMaterialDocument(callback){if(pageChangeSubscribed){return true;}
if(typeof document$==='undefined'||typeof document$.subscribe!=='function'){return false;}
document$.subscribe(()=>{callback();});pageChangeSubscribed=true;clearObserverWaitTimer();return true;}
function subscribeToPageChanges(callback){const runNow=()=>{afterNextPaint(()=>{callback();});};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',runNow,{once:true});}else{runNow();}
if(trySubscribeToMaterialDocument(callback)){return;}
let waitCount=0;clearObserverWaitTimer();observerWaitTimer=window.setInterval(()=>{waitCount+=1;if(trySubscribeToMaterialDocument(callback)){return;}
if(waitCount>=MATERIAL_OBSERVER_MAX_WAIT_COUNT){clearObserverWaitTimer();}},MATERIAL_OBSERVER_POLL_INTERVAL);}
function observeDomChanges(){if(domObserver||typeof MutationObserver==='undefined'){return;}
domObserver=new MutationObserver(()=>{if(shouldAttemptMount()){scheduleMountWaline();}});domObserver.observe(document.documentElement,{childList:true,subtree:true});}
subscribeToPageChanges(()=>{scheduleMountWaline();observeDomChanges();});})();